rss.channel:
      {% if order == 'deleted' %}
        {{ config['MYSERVER_NAME_SHORT'] }}:Channels:Deleted
        https://{{ config['MYSERVER_NAME'] }}/channel/deleted
        
        {{ channelcount | viewdisplay }} Deleted Channels
          
            https://{{ config['MYSERVER_NAME'] }}/alt_favicon_140_140.jpg
            {{ config['MYSERVER_NAME_SHORT'] }}:Channels
            https://{{ config['MYSERVER_NAME'] }}
          
      {% else %}
        {{ config['MYSERVER_NAME_SHORT'] }}:Channels
        https://{{ config['MYSERVER_NAME'] }}/channel
        
        {{ channelcount | viewdisplay }} Monitored/Archived Channels
          
            https://{{ config['MYSERVER_NAME'] }}/alt_favicon_140_140.jpg
            {{ config['MYSERVER_NAME_SHORT'] }}:Channels
            https://{{ config['MYSERVER_NAME'] }}
          
      {% endif %}
          {% for channel in channels %}


              {{ channel['ytc_title']  }}
              https://{{ config['MYSERVER_NAME'] }}{{ url_for('channel.item', ytc_id=channel['ytc_id']) }}
              https://{{ config['MYSERVER_NAME'] }}{{ url_for('channel.item', ytc_id=channel['ytc_id']) }}
              
                <a href="https://{{ config['MYSERVER_NAME'] }}{{ url_for('channel.item', ytc_id=channel['ytc_id']) }}">
                  <img 
                   src="{{ channel['ytc_thumbnailurl'] | reverse | replace('88','671', 1) | reverse  }}" >
                  </style>
                </a>
                <p>
                <b>Total Videos: {{ channel['total'] }}</b><br>
                <b>Limited/Deleted Videos: {{ channel['limited'] }}</b><br>
                <b>Views: {{ channel['ytc_viewcount'] }}</b><br>
                <b>Subscribers: {{ channel['ytc_subscribercount'] }}</b><br>
                <b>Created: {{ channel['ytc_publishedat'].strftime('%b %e, %G') }}</b><br>
              {% if channel['ytc_deleted'] %}
                 <b>Deleted: {{ channel['ytc_deleteddate'].strftime('%b %e, %G') }}</b><br>
              {% endif %}
              <p>
                {{ channel['ytc_description'] | linkify | safe | nl2br | truncate (1200) }} 
              


                YouTube Channel ID: {{ channel['ytc_id'] }}

                YouTube Channel URL: https://www.youtube.com/channel/{{ channel['ytc_id'] }}

              
            
          {% endfor %}
